import React, { Fragment, useState, useEffect } from "react";
import {
  Col,
  Card,
  CardHeader,
  CardBody,
  Form,
  FormGroup,
  Label,
  Row,
} from "reactstrap";
import { Btn, H3, Breadcrumbs } from "../../../AbstractElements";
import { useForm } from "react-hook-form";
import { useNavigate } from "react-router-dom";
import {
 
  AddproblemTitle,

  Description,
  EidtproblemTitle,
  problem,
  problemName,
  Save,
} from "../../../Constant";
import {

  addProblemType,
  addProblemTypeRole,

  showProblemsType,
  showProblemsTypeRole, updateProblemType,
  updateProblemTypeRole,
} from "../../../CommonUrl";
import { useSelector } from "react-redux";
import { getClientUrlDataToken, postClientUrlWithToken } from "../../../Utils/restUtils";
import { toast } from "react-toastify";
import Transparentspinner from "../../Common/Loader/Transparentspinner";
import { yupResolver } from "@hookform/resolvers/yup";
import * as yup from "yup";

const schema = yup.object().shape({
  brand_name: yup.string().required().label("Problem Type"),
});
const AddEditProblemType = () => {
  const {
    register,
    handleSubmit,
    setValue,
    formState: { errors },
  } = useForm({
    resolver: yupResolver(schema),
  });
  const authState = useSelector((state) => state.auth);
  const searchParams = location.search;
  const params = new URLSearchParams(searchParams);
  const param1 = params.get("id");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();


  const onSubmit = async (data) => {
    setLoading(true);
    const postRequest = {
      description: data?.description,
      name: data?.brand_name,
      ...(param1 && { problem_type_id: param1 }),
    };

    let result
    if (param1) {

      result = await postClientUrlWithToken(
        authState.apiUrl,
        authState.userRole === 1 ? updateProblemType : updateProblemTypeRole,
        postRequest
      );
    }
    else {
      result = await postClientUrlWithToken(
        authState.apiUrl,
        authState.userRole === 1 ? addProblemType : addProblemTypeRole,
        postRequest
      );
    }
    if (result?.status === 200) {
      if (result.data.status === true) {
        toast.success(result.data.message);
        navigate(`${process.env.PUBLIC_URL}/settings/problem-type`);
      } else {
        toast.error(result.data.message);
        setLoading(false);
      }
    } else if (result.status >= 400 && result.status <= 405) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
    } else if (result.status >= 500 && result.status <= 505) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
    } else {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
    }
    setLoading(false);
  };

  const handlegetBrandDetails = async () => {
    setLoading(true);
    let responce = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? showProblemsType + `?problem_type_id=${param1}` : showProblemsTypeRole + `?problem_type_id=${param1}`);
    if (responce.status === true) {
      setValue('brand_name', responce?.data?.data[0]?.name);
      setValue('description', responce?.data?.data[0]?.description);
    }
    else if (data.status >= 400 && data.status <= 405) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
    } else if (data.status >= 500 && data.status <= 505) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
    }
    else {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);

    }
    setLoading(false);
  }

  useEffect(() => {
    if (param1) {
      handlegetBrandDetails()
    }
  }, [])
  return (
    <Fragment>
      {loading && <Transparentspinner />}

      <Breadcrumbs
        mainTitle={problem}
        parent="Settings"
        title={param1 ? EidtproblemTitle : AddproblemTitle}
      />
      <Card>
        <CardHeader className="pb-0">
          <H3>{param1 ? EidtproblemTitle : AddproblemTitle}</H3>
        </CardHeader>
        <CardBody>
          <Form
            className="needs-validation"
            noValidate
            onSubmit={handleSubmit(onSubmit)}
          >
            <Row className="g-3 pt-3">
              <Col md="6">
                <Label className="form-label" for="area-name">
                  {problemName}
                  <span className="requireStar">*</span>
                </Label>
                <input
                  className="form-control"
                  id="brand_name"
                  type="text"
                  {...register("brand_name", { required: true })}
                />
                <span className="text-danger">
                  {errors?.brand_name?.message}
                </span>
              </Col>
              <Col md="6">
                <Label className="form-label" for="area_code">
                  {Description}
                </Label>
                <textarea
                  className="form-control"
                  id="description"
                  {...register("description")}
                ></textarea>

              </Col>
            </Row>
            <FormGroup></FormGroup>
            <Btn attrBtn={{ color: "primary" }} type="submit">
              {Save}
            </Btn>
          </Form>
        </CardBody>
      </Card>
    </Fragment>
  );
};
export default AddEditProblemType;
